using System.ComponentModel;
using System.Net;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient pipeline with iteration guard ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(c => c.MaximumIterationsPerRequest = 10)
    .Build();

// --- Define tools ---
var notebook = new ResearchNotebook();
var searcher = new WebSearcher();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searcher.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Create the research agent ---
var agent = chatClient.AsAIAgent(new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics by searching the web and taking notes.",
    UseProvidedChatClientAsIs = true,
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
        Tools = tools,
    },
},
instructions: """
    You are a thorough research assistant. When given a topic:

    1. Search the web with at least 3 different, varied queries to gather diverse information.
    2. After each search, save the most important findings as a note using the note-taking tool.
    3. Once you have gathered enough information, retrieve all notes and write a comprehensive summary.

    Always cite the key facts you found. Be thorough but concise.
    """);

// --- Interactive loop ---
Console.WriteLine("🔍 Research Agent");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("> ");

while (Console.ReadLine() is { } topic && !topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Write("> ");
        continue;
    }

    Console.WriteLine($"\nResearching: {topic}\n");
    notebook.Clear();

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {topic}");

        Console.WriteLine("\n📋 Research Summary:");
        Console.WriteLine(new string('─', 60));
        Console.WriteLine(response.Text);
        Console.WriteLine(new string('─', 60));

        if (response.Usage is { } usage)
        {
            Console.WriteLine(
                $"Tokens used — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }

    Console.WriteLine("\nEnter another topic (or 'quit' to exit):");
    Console.Write("> ");
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Provides web search via DuckDuckGo's HTML endpoint.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Search the web for information. Returns text snippets from search results.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await s_http.GetStringAsync(url, cancellationToken);
            var results = ExtractResults(html);

            return results.Count == 0
                ? $"No results found for: {query}"
                : $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static List<string> ExtractResults(string html)
    {
        var results = new List<string>();
        var titles = ExtractByClass(html, "result__a");
        var snippets = ExtractByClass(html, "result__snippet");

        for (int i = 0; i < Math.Min(5, Math.Max(titles.Count, snippets.Count)); i++)
        {
            var entry = new StringBuilder();
            if (i < titles.Count)
                entry.AppendLine($"**{titles[i]}**");
            if (i < snippets.Count)
                entry.AppendLine(snippets[i]);
            results.Add(entry.ToString().TrimEnd());
        }

        return results;
    }

    private static List<string> ExtractByClass(string html, string className)
    {
        var items = new List<string>();
        var marker = $"class=\"{className}\"";
        int pos = 0;

        while ((pos = html.IndexOf(marker, pos, StringComparison.Ordinal)) >= 0)
        {
            pos += marker.Length;
            var open = html.IndexOf('>', pos);
            if (open < 0) break;

            var close = html.IndexOf('<', open + 1);
            if (close < 0) break;

            var text = WebUtility.HtmlDecode(html[(open + 1)..close]).Trim();
            if (!string.IsNullOrWhiteSpace(text))
                items.Add(text);
        }

        return items;
    }
}

/// <summary>In-memory notebook for storing research findings.</summary>
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description(
        "Save a research note. Use this to record important findings from web searches.")]
    public string SaveNote(
        [Description("Short descriptive title")] string title,
        [Description("Detailed content of the finding")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description(
        "Retrieve all saved research notes. Call this before writing the final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} Research Notes ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        Console.WriteLine($"  📖 Retrieved {_notes.Count} notes");
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

